import re

def parse_imports(file_content):
    import_pattern = re.compile(r'^\s*(?:import|from)\s+([\w\.]+)', re.MULTILINE)
    matches = import_pattern.findall(file_content)
    unique_modules = set(matches)
    return sorted(unique_modules)

