import heapq

def dijkstra(graph, start):
    """
    Dijkstra's shortest path algorithm.

    Args:
        graph: dict of {node: [(neighbor, weight), ...]}
        start: starting node

    Returns:
        distances: dict of {node: shortest_distance_from_start}
        predecessors: dict of {node: previous_node_in_shortest_path}
    """
    distances = {node: float('inf') for node in graph}
    distances[start] = 0
    predecessors = {node: None for node in graph}

    priority_queue = [(0, start)]
    visited = set()

    while priority_queue:
        current_dist, current_node = heapq.heappop(priority_queue)

        if current_node in visited:
            continue
        visited.add(current_node)

        for neighbor, weight in graph[current_node]:
            if neighbor not in distances:
                distances[neighbor] = float('inf')
                predecessors[neighbor] = None

            distance = current_dist + weight

            if distance < distances[neighbor]:
                distances[neighbor] = distance
                predecessors[neighbor] = current_node
                heapq.heappush(priority_queue, (distance, neighbor))

    return distances, predecessors


def get_shortest_path(predecessors, start, end):
    """
    Reconstruct the shortest path from start to end.

    Args:
        predecessors: dict from dijkstra()
        start: starting node
        end: ending node

    Returns:
        list of nodes representing the shortest path, or None if no path exists
    """
    path = []
    current = end

    while current is not None:
        path.append(current)
        if current == start:
            break
        current = predecessors.get(current)
    else:
        return None

    path.reverse()

    if path[0] != start:
        return None

    return path


