                "type": "object",
                "properties": {
                    "edges": {
                        "type": "array",
                        "description": "List of edges in the graph",
                        "items": {
                            "type": "object",
                            "properties": {
                                "from": {"type": "string", "description": "Source node"},
                                "to": {"type": "string", "description": "Destination node"},
                                "weight": {"type": "number", "description": "Edge weight"}
                            },
                            "required": ["from", "to", "weight"]
                        }
                    },
                    "directed": {
                        "type": "boolean",
                        "description": "Whether the graph is directed"
                    }
                },
                "required": ["edges", "directed"]
            }
        }
    ]

    message = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        tools=tools,
        messages=[
            {
                "role": "user",
                "content": f"Parse this graph description and create the adjacency list: {description}"
            }
        ]
    )

    graph = defaultdict(list)

    for content in message.content:
        if content.type == "tool_use" and content.name == "create_graph":
            edges = content.input["edges"]
            directed = content.input["directed"]

            for edge in edges:
                from_node = edge["from"]
                to_node = edge["to"]
                weight = edge["weight"]

                graph[from_node].append((to_node, weight))

                if not directed:
                    graph[to_node].append((from_node, weight))

    return dict(graph)


