def tokenize(text):
    """Simple tokenization by splitting on whitespace and converting to lowercase."""
    return text.lower().split()

def compute_bm25(query: str, corpus: list[str], k1: float = 1.5, b: float = 0.75) -> list[dict]:
    """
    Compute BM25 scores for a query against a corpus of documents.

    Args:
        query: The search query
        corpus: List of documents
        k1: Term frequency saturation parameter
        b: Length normalization parameter

    Returns:
        List of dicts with document index, content, and BM25 score
    """
    N = len(corpus)

    tokenized_corpus = [tokenize(doc) for doc in corpus]
    doc_lengths = [len(doc) for doc in tokenized_corpus]
    avg_doc_length = sum(doc_lengths) / N if N > 0 else 0

    df = {}
    for doc_tokens in tokenized_corpus:
        unique_terms = set(doc_tokens)
        for term in unique_terms:
            df[term] = df.get(term, 0) + 1

    query_terms = tokenize(query)

    scores = []
    for doc_idx, doc_tokens in enumerate(tokenized_corpus):
        tf = Counter(doc_tokens)
        doc_length = doc_lengths[doc_idx]

        score = 0.0
        for term in query_terms:
            if term not in tf:
                continue

            term_freq = tf[term]
            doc_freq = df.get(term, 0)

            idf = math.log((N - doc_freq + 0.5) / (doc_freq + 0.5) + 1)

            tf_normalized = (term_freq * (k1 + 1)) / (
                term_freq + k1 * (1 - b + b * doc_length / avg_doc_length)
            )

            score += idf * tf_normalized

        scores.append({
            "doc_index": doc_idx,
            "document": corpus[doc_idx],
            "score": score
        })

    scores.sort(key=lambda x: x["score"], reverse=True)
    return scores

