from collections import defaultdict

class BM25:
    def __init__(self, documents):
        self.documents = documents
        self.total_documents = len(self.documents)
        self.avg_doc_length = sum(len(doc) for doc in documents) / self.total_documents
        self.term_frequencies = [defaultdict(int) for _ in range(self.total_documents)]
        self.document_frequencies = defaultdict(int)
        self.inverse_document_frequencies = {}
        self.document_lengths = []
        self.index()

    def index(self):
        for doc_idx, document in enumerate(self.documents):
            self.document_lengths.append(len(document))
            unique_terms = set(document)
            for term in document:
                self.term_frequencies[doc_idx][term] += 1
            for term in unique_terms:
                self.document_frequencies[term] += 1
        self.calculate_idf()

    def calculate_idf(self):
        for term, freq in self.document_frequencies.items():
            self.inverse_document_frequencies[term] = math.log((self.total_documents - freq + 0.5) / (freq + 0.5) + 1)

    def score(self, query, k1=1.5, b=0.75):
        scores = []
        for doc_idx, document in enumerate(self.documents):
            score = 0.0
            doc_length = self.document_lengths[doc_idx]
            for term in query:
                if term not in self.term_frequencies[doc_idx]:
                    continue
                tf = self.term_frequencies[doc_idx][term]
                idf = self.inverse_document_frequencies.get(term, 0)
                term_score = idf * (tf * (k1 + 1)) / (tf + k1 * (1 - b + b * doc_length / self.avg_doc_length))
                score += term_score
            scores.append(score)
        return scores

def compute_bm25(corpus, query):
    bm25 = BM25(corpus)
    return bm25.score(query)

import math
from collections import Counter

class BM25:
    def __init__(self, corpus, k1=1.5, b=0.75):
        self.k1 = k1
        self.b = b
        self.corpus_size = len(corpus)
        self.avgdl = sum(len(doc) for doc in corpus) / self.corpus_size
        self.doc_freqs = []
        self.doc_lens = []
        self.avg_idf = 0
        self.idf = {}

        self._initialize(corpus)

    def _initialize(self, corpus):
        df = {}
        for doc in corpus:
            self.doc_lens.append(len(doc))
            frequencies = Counter(doc)
            self.doc_freqs.append(frequencies)
            for word, freq in frequencies.items():
                if word not in df:
                    df[word] = 0
                df[word] += 1

        self.idf = {
            word: math.log(1 + (self.corpus_size - freq + 0.5) / (freq + 0.5))
            for word, freq in df.items()
        }
        self.avg_idf = sum(self.idf.values()) / len(self.idf)

    def score(self, query, index):
        score = 0.0
        doc_len = self.doc_lens[index]
        frequencies = self.doc_freqs[index]

        for word in query:
            if word not in frequencies:
                continue

            freq = frequencies[word]
            idf = self.idf.get(word, self.avg_idf)

            numerator = freq * (self.k1 + 1)
            denominator = freq + self.k1 * (1 - self.b + self.b * doc_len / self.avgdl)
            score += idf * (numerator / denominator)

        return score

    def get_scores(self, query):
        scores = []
        for index in range(self.corpus_size):
            scores.append(self.score(query, index))
        return scores

