import time
import functools
import random


def retry(max_attempts=3, initial_delay=1.0, backoff_factor=2.0, jitter=True, exceptions=(Exception,)):
    """
    A decorator that retries a function up to max_attempts times on exception,
    with exponential backoff.

    Args:
        max_attempts: Maximum number of attempts (default: 3)
        initial_delay: Initial delay in seconds between retries (default: 1.0)
        backoff_factor: Multiplier for delay after each retry (default: 2.0)
        jitter: Add random jitter to delay to avoid thundering herd (default: True)
        exceptions: Tuple of exception types to catch (default: (Exception,))
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            delay = initial_delay
            last_exception = None

            for attempt in range(1, max_attempts + 1):
                try:
                    result = func(*args, **kwargs)
                    if attempt > 1:
                        print(f"Success on attempt {attempt}/{max_attempts}")
                    return result
                except exceptions as e:
                    last_exception = e
                    if attempt == max_attempts:
                        print(f"All {max_attempts} attempts failed. Last error: {e}")
                        raise

                    sleep_time = delay
                    if jitter:
                        sleep_time = delay * (0.5 + random.random())

                    print(f"Attempt {attempt}/{max_attempts} failed: {e}. Retrying in {sleep_time:.2f}s...")
                    time.sleep(sleep_time)
                    delay *= backoff_factor

            raise last_exception

        return wrapper
    return decorator


